import{z as l,x as s,b as i,c as m,i as o}from"./index-dc5fff9e.js";const a={class:"markdown-body"},r=o("<h3>1. 安装</h3><ul><li>命令：apt-get install mariadb-server 运行 mysql_secure_installation 脚本以解决默认MariaDB安装中的几个安全问题：</li></ul><h3>2. 登录</h3><ul><li>登录 : mysql -u root -p</li><li>重置ROOT密码 : service mariadb stop &amp;&amp; mysqld_safe --skip-grant-tables &amp;</li></ul><h3>3. 命令</h3><ul><li><p>创建数据库: CREATE DATABASE <em>DATABASENAME</em>;</p></li><li><p>创建用户: CREATE USER ‘<em>USERNAME</em>’@‘<em>IP</em>’ IDENTIFIED BY ‘<em>PASSWORD</em>’;</p></li><li><p>删除用户: DROP USER ‘<em>USERNAME</em>’@‘<em>IP</em>’;</p></li><li><p>用户数据库权限: GRANT <em>AUTHORITY</em> ON <em>DATABASENAME</em>.* TO ‘<em>USERNAME</em>’ IDENTIFIED BY ‘<em>PASSWORD</em>’;</p><ul><li><em>AUTHORITY</em> : ALL , SELECT , UPDATE , INSERT , CREATE ,ALTER , DELETE , DROP , GRANT , REVOKE , INDEX</li><li>常用密码：enB3MTk5Mw==</li></ul></li><li><p>查看数据库: SHOW DATABASES:</p></li><li><p>查看数据表：SHOW TABLES;</p></li><li><p>显示用户权限：show grants;</p></li><li><p>数据库状态：show status;</p></li><li><p>显示用户：select user,host from <em>DATABASENAME</em>.user; // select * from mysql.user;</p></li><li><p>查询用户：show processlist;</p></li></ul>",6),p=[r],n={layout:"post",title:"MariaDB数据库",series:"techs",modtime:"2024/08/20"},T="",R=l({__name:"blog",setup(E,{expose:t}){t({frontmatter:{layout:"post",title:"MariaDB数据库",series:"techs",modtime:"2024/08/20"},excerpt:void 0});const e=s();return e.currentRoute.value.meta={...e.currentRoute.value.meta,layout:"post"},(A,u)=>(i(),m("div",a,p))}});export{R as default,T as excerpt,n as frontmatter};
